import { useState } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async () => {
    if (!file) return alert("Please select an image");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Something went wrong!");
    }

    setLoading(false);
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <h1 style={styles.title}>🚗 ClaimPilot AI</h1>
        <p style={styles.subtitle}>
          AI-powered vehicle damage assessment & fraud detection
        </p>

        <label style={styles.uploadBox}>
          {file ? file.name : "📂 Click to upload vehicle damage image"}
          <input
            type="file"
            accept="image/*"
            style={{ display: "none" }}
            onChange={(e) => setFile(e.target.files[0])}
          />
        </label>

        <button
          onClick={handleUpload}
          style={loading ? styles.buttonLoading : styles.button}
        >
          {loading ? "Analyzing with AI..." : "Run AI Audit"}
        </button>

        {result && (
          <div style={styles.resultBox}>
            <h2 style={styles.resultTitle}>📊 Audit Report</h2>

            <div style={styles.grid}>
              <div style={styles.statCard}>
                <p>Total Estimate</p>
                <h3>PKR {result.total_estimate_pkr}</h3>
              </div>

              <div style={styles.statCard}>
                <p>Fraud Score</p>
                <h3>{result.fraud_confidence_score}</h3>
              </div>
            </div>

            <p><strong>Verdict:</strong> {result.verdict}</p>
            <p><strong>Fraud Analysis:</strong> {result.fraud_analysis}</p>

            <h3>Damaged Parts</h3>
            <ul>
              {result.damaged_parts?.map((part, index) => (
                <li key={index}>{part}</li>
              ))}
            </ul>

            <h3>Itemized Costs</h3>
            <pre style={styles.pre}>
              {JSON.stringify(result.itemized_costs, null, 2)}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #1f1c2c, #928dab)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },

  card: {
    background: "rgba(255, 255, 255, 0.1)",
    backdropFilter: "blur(20px)",
    borderRadius: "20px",
    padding: "40px",
    width: "100%",
    maxWidth: "700px",
    color: "white",
    boxShadow: "0 20px 50px rgba(0,0,0,0.4)",
  },

  title: {
    fontSize: "32px",
    marginBottom: "10px",
    fontWeight: "700",
  },

  subtitle: {
    opacity: 0.8,
    marginBottom: "30px",
  },

  uploadBox: {
    display: "block",
    border: "2px dashed rgba(255,255,255,0.5)",
    padding: "20px",
    borderRadius: "12px",
    cursor: "pointer",
    marginBottom: "20px",
    transition: "0.3s",
    textAlign: "center",
  },

  button: {
    width: "100%",
    padding: "15px",
    borderRadius: "12px",
    border: "none",
    background: "linear-gradient(90deg, #00c6ff, #0072ff)",
    color: "white",
    fontSize: "16px",
    fontWeight: "600",
    cursor: "pointer",
    transition: "0.3s",
  },

  buttonLoading: {
    width: "100%",
    padding: "15px",
    borderRadius: "12px",
    border: "none",
    background: "gray",
    color: "white",
    fontSize: "16px",
    fontWeight: "600",
    cursor: "not-allowed",
  },

  resultBox: {
    marginTop: "30px",
    background: "rgba(0,0,0,0.3)",
    padding: "20px",
    borderRadius: "15px",
  },

  resultTitle: {
    marginBottom: "20px",
  },

  grid: {
    display: "flex",
    gap: "15px",
    marginBottom: "20px",
  },

  statCard: {
    flex: 1,
    background: "rgba(255,255,255,0.1)",
    padding: "15px",
    borderRadius: "12px",
    textAlign: "center",
  },

  pre: {
    background: "black",
    padding: "10px",
    borderRadius: "8px",
    overflowX: "auto",
    fontSize: "13px",
  },
};

export default App;
